```swift
import Foundation
import CryptoKit

func generateJWT(user: User, secretKey: String) -> String? {
    let header = "{\"alg\":\"HS256\",\"typ\":\"JWT\"}".data(using: .utf8)?.base64EncodedString()

    let expirationTime = Date().addingTimeInterval(3600).timeIntervalSince1970
    let payload = "{\"userId\":\"\(user.userId)\",\"clientToken\":\"\(user.clientToken)\",\"exp\":\(expirationTime)}".data(using: .utf8)?.base64EncodedString()

    let dataToSign = "\(header ?? "").\(payload ?? "")"
    guard let data = dataToSign.data(using: .utf8) else { return nil }

    let key = SymmetricKey(data: Data(base64Encoded: secretKey)!)
    let signature = HMAC<SHA256>.authenticationCode(for: data, using: key).compactMap { String(format: "%02x", $0) }.joined()

    return "\(dataToSign).\(signature)"
}

// Example usage
let user = User(userId: "12345", clientToken: "abcde")
let secretKey = "your_secret_key_here"
if let jwt = generateJWT(user: user, secretKey: secretKey) {
    print(jwt)
} else {
    print("Failed to generate JWT")
}
```

This solution defines a function `generateJWT` that takes a `User` object and a secret key as input and returns a JWT string. It constructs the JWT according to the JWT standard, including the header, payload, and signature. The HMAC SHA-256 algorithm is used to sign the JWT with the secret key, and the expiration time is set to 1 hour from the current time. The function returns the generated JWT string or `nil` if there is an error in the process.

