```javascript
function createCombinations(arr) {
  const primes = getPrimes(arr);
  const combinations = [];

  for (let k = 2; k <= 10; k += 2) {
    const subset = [];
    generateCombinations(arr, subset, 0, k, combinations, primes);
  }

  return combinations;
}

function generateCombinations(arr, subset, index, k, combinations, primes) {
  if (subset.length === k) {
    combinations.push(subset.slice());
    return;
  }

  for (let i = index; i < arr.length; i++) {
    subset.push(arr[i]);
    generateCombinations(arr, subset, i + 1, k, combinations, primes);
    subset.pop();
  }
}

function getPrimes(arr) {
  const primes = [];
  for (let i = 0; i < arr.length; i++) {
    if (isPrime(arr[i])) {
