public class QJ_FileCenterService : ServiceBase
{
    private FileSystemWatcher fileSystemWatcher;
    private string monitoredDirectory = "C:\\MonitoredDirectory"; // Replace with the actual directory path to monitor

    public QJ_FileCenterService()
    {
        ServiceName = "QJ_FileCenterService";
    }

    protected override void OnStart(string[] args)
    {
        InitializeFileSystemWatcher();
    }

    protected override void OnStop()
    {
        fileSystemWatcher.Dispose();
    }

    private void InitializeFileSystemWatcher()
    {
        fileSystemWatcher = new FileSystemWatcher();
        fileSystemWatcher.Path = monitoredDirectory;
        fileSystemWatcher.NotifyFilter = NotifyFilters.FileName | NotifyFilters.LastWrite | NotifyFilters.CreationTime | NotifyFilters.Deletion;
        fileSystemWatcher.Filter = "*.*";
        fileSystemWatcher.IncludeSubdirectories = false;

        fileSystemWatcher.Created += OnFileCreated;
        fileSystemWatcher.Deleted += OnFileDeleted;
        fileSystemWatcher.Changed += OnFileModified;

        fileSystemWatcher.EnableRaisingEvents = true;
    }

    private void OnFileCreated(object sender, FileSystemEventArgs e)
    {
        Console.WriteLine($"File created: {e.Name}");
        // Perform additional actions for file creation if needed
    }

    private void OnFileDeleted(object sender, FileSystemEventArgs e)
    {
