Here is an updated version of the function that addresses the requirements:

```R
median_custom <- function(data.set) {
  if(all(is.na(data.set))) {
    return("NA")
  } else if(all(is.numeric(data.set))) {
    unique_values <- sort(unique(data.set))
    n <- length(unique_values)
    median_index <- ifelse(n %% 2 == 0, c(n/2, n/2 + 1), (n + 1)/2)
    median_value <- unique_values[median_index]
    return(as.character(median_value))
  } else {
    unique_values <- sort(unique(data.set))
    counts <- table(data.set)
    mode <- unique_values[which.max(counts)]
    return(as.character(mode))
  }
}
```

