function randomizeWithNoConsecutiveSameStartingLetter(array) {
  let swaps = 0;

  // Helper function to check if two words have the same starting letter
  function hasSameStartingLetter(word1, word2) {
    return word1.charAt(0).toLowerCase() === word2.charAt(0).toLowerCase();
  }

  // Helper function to generate a random index within the array
  function getRandomIndex(array) {
    return Math.floor(Math.random() * array.length);
  }

  // Helper function to swap two elements in the array
  function swap(array, index1, index2) {
    const temp = array[index1];
    array[index1] = array[index2];
    array[index2] = temp;
  }

  // Shuffle the array using Fisher-Yates algorithm
  for (let i = array.length - 1; i > 0; i--) {
    const j = getRandomIndex(array);
    swap(array, i, j);

    if (i > 0 && hasSameStartingLetter(array[i], array[i - 1])) {
      const k = getRandomIndex(array);
      swap(array, i, k);
      swaps++;
    }
  }

  return [array, swaps];
}

const array = ["apple", "banana", "cherry", "date", "elderberry", "fig", "grape", "honeydew"];
console.log(randomizeWithNoConsecutiveSameStartingLetter(array));
```

This function uses the Fisher-Yates algorithm to shuffle the array randomly. It also checks if any consecutive elements have the same starting letter, and if so, swaps one of them with another randomly chosen element in the array. Finally, it returns the randomized array and the number of swaps made as an array.

