Here's an example of a JavaScript class that generates random numbers within a specific range and with a specific distribution:

```javascript
class RandomNumberGenerator {
  constructor(min, max) {
    this.min = min;
    this.max = max;
    this.numbers = [];
  }

  // Generate random numbers with normal distribution
  generateNormalDistribution(mean, stdDev, count) {
    for (let i = 0; i < count; i++) {
      const number = this.generateRandomNumber();
      const normalNumber = this.calculateNormalDistribution(number, mean, stdDev);
      this.numbers.push(normalNumber);
    }
  }

  // Generate random numbers with exponential distribution
  generateExponentialDistribution(lambda, count) {
    for (let i = 0; i < count; i++) {
      const number = this.generateRandomNumber();
      const exponentialNumber = this.calculateExponentialDistribution(number, lambda);
      this.numbers.push(exponentialNumber);
    }
  }

  // Generate a random number within the given range
  generateRandomNumber() {
    return Math.random() * (this.max - this.min) + this.min;
  }

  // Calculate the normal distribution of a number
  calculateNormalDistribution(x, mean, stdDev) {
    return (1 / (stdDev * Math.sqrt(2 * Math.PI))) * Math.exp(-Math.pow((x - mean), 2) / (2 * Math.pow(stdDev, 2)));
  }

  // Calculate the exponential distribution of a number
  calculateExponentialDistribution(x, lambda) {
    return lambda * Math.exp(-lambda * x);
  }

  // Calculate the mean of generated numbers
  calculateMean() {
    const sum = this.numbers.reduce((acc, val) => acc + val, 0);
    return sum / this.numbers.length;
  }

  // Calculate the standard deviation of generated numbers
  calculateStdDev() {
    const mean = this.calculateMean();
    const variance = this.numbers.reduce((acc, val) => acc + Math.pow(val - mean, 2), 0) / this.numbers.length;
    return Math.sqrt(variance);
  }

  // Calculate the mode of generated numbers
  calculateMode() {
    const frequencies = {};
    let maxFrequency = 0;
    let mode = [];

    for (const number of this.numbers) {
      frequencies[number] = (frequencies[number] || 0) + 1;
      if (frequencies[number] > maxFrequency) {
        maxFrequency = frequencies[number];
        mode = [number];
      } else if (frequencies[number] === maxFrequency) {
        mode.push(number);
      }
    }

    return mode;
  }
}
```

Example usage:

```javascript
const rng = new RandomNumberGenerator(1, 10);

rng.generateNormalDistribution(5, 1, 100);
console.log(rng.calculateMean()); // Output: 5
console.log(rng.calculateStdDev()); // Output: 1

rng.generateExponentialDistribution(0.5, 100);
console.log(rng.calculateMean()); // Output: 2
console.log(rng.calculateStdDev()); // Output: 2

rng.generateNormalDistribution(3, 1, 100);
console.log(rng.calculateMode()); // Output: [3]
```

