Car.prototype.calculateFuelConsumption = function(mileage, fuelTankCapacity, fuelType) {
  if (mileage <= 0 || fuelTankCapacity <= 0 || fuelTankCapacity > 100) {
    return "Invalid inputs";
  }

  let fuelEfficiency = 0;

  switch(fuelType) {
    case "gasoline":
      fuelEfficiency = mileage / fuelTankCapacity;
      break;
    case "diesel":
      fuelEfficiency = mileage / (fuelTankCapacity * 1.1);
      break;
    case "hybrid":
      fuelEfficiency = mileage / (fuelTankCapacity * 1.3);
      break;
    case "electric":
      fuelEfficiency = mileage / (fuelTankCapacity * 0.8);
      break;
    default:
      return "Invalid fuel type";
  }

  return fuelEfficiency.toFixed(2) + " miles per gallon";
};

// Function to compare fuel efficiency of two cars
function compareFuelEfficiency(car1, car2) {
  if (car1.mileage > 500000 || car2.mileage > 500000) {
    return "Invalid mileage";
  }

  const car1Efficiency = car1.mileage / car1.fuelTankCapacity;
  const car2Efficiency = car2.mileage / car2.fuelTankCapacity;

  if (car1Efficiency > car2Efficiency) {
    return car1.make + " " + car1.model + " is more fuel efficient";
  } else if (car2Efficiency > car1Efficiency) {
    return car2.make + " " + car2.model + " is more fuel efficient";
  } else {
    return "Both cars have the same fuel efficiency";
  }
}

// Method to track and display the number of times the car has been driven
Car.prototype.trackDrivenTimes = function() {
  this.drivenTimes++;
  return this.drivenTimes;
};

// Method to track and display the total distance driven by the car
Car.prototype.trackTotalDistance = function(distance) {
  if (distance <= 0 || distance > 500000) {
    return "Invalid distance";
  }

  this.totalDistance += distance;
  return this.totalDistance;
};

