Here's an example of how you can create a JavaScript object to store the bird names and their corresponding encrypted scientific names using a randomly generated Vigenère cipher keyword:

```javascript
// Function to generate a random keyword of length between 3 and 6
function generateRandomKeyword() {
  const possibleChars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ';
  const keywordLength = Math.floor(Math.random() * 4) + 3;
  let keyword = '';
  for (let i = 0; i < keywordLength; i++) {
    const randomIndex = Math.floor(Math.random() * possibleChars.length);
    keyword += possibleChars[randomIndex];
  }
  return keyword;
}

// Function to encrypt a string using Vigenère cipher
function encryptWithVigenere(text, keyword) {
  const charCodeA = 'A'.charCodeAt(0);
  const cipherText = [];
  for (let i = 0; i < text.length; i++) {
    const char = text[i].toUpperCase();
    const keywordChar = keyword[i % keyword.length].toUpperCase();
    const keywordCharIndex = keywordChar.charCodeAt(0) - charCodeA;
    const encryptedChar = String.fromCharCode(((char.charCodeAt(0) - charCodeA + keywordCharIndex) % 26) + charCodeA);
    cipherText.push(encryptedChar);
  }
  return cipherText.join('');
}

// Create an object to store bird names and encrypted scientific names
const birds = {
  "Robin": encryptWithVigenere("Erjpm", generateRandomKeyword()),
  "Eagle": encryptWithVigenere("Iwrig", generateRandomKeyword()),
  "Sparrow": encryptWithVigenere("Wdpsori", generateRandomKeyword()),
  "Hawk": encryptWithVigenere("Ihqo", generateRandomKeyword()),
