  "Owl": encryptWithVigenere("Zem", generateRandomKeyword()),
  "Penguin": encryptWithVigenere("Rfhpxuh", generateRandomKeyword()),
  "Parrot": encryptWithVigenere("Rfutvw", generateRandomKeyword()),
