#!/bin/bash

usage() {
  echo "Usage: $0 -c <color> -f <format>"
  echo "Options:"
  echo "  -c, --color <color>   Specify the color of the message (red, green, yellow, blue, magenta, cyan, white)"
  echo "  -f, --format <format> Specify the formatting of the message (bold, underline, italic)"
  exit 1
}

msg() {
  local color=$1
  local format=$2
  local message=$3

  case $color in
    red) color_code="31";;
    green) color_code="32";;
    yellow) color_code="33";;
    blue) color_code="34";;
    magenta) color_code="35";;
    cyan) color_code="36";;
    white) color_code="37";;
    *) echo "Invalid color"; exit 1;;
  esac

  case $format in
    bold) format_code="1";;
    underline) format_code="4";;
    italic) format_code="3";;
    *) echo "Invalid format"; exit 1;;
  esac

  echo -e "\033[${format_code};${color_code}m${message}\033[0m"
}

while [[ $# -gt 0 ]]; do
  case $1 in
    -c|--color)
      color=$2
      shift 2
      ;;
    -f|--format)
      format=$2
      shift 2
      ;;
    *)
      usage
      ;;
  esac
done

if [[ -z $color || -z $format ]]; then
  usage
fi

read -p "Enter your message: " message
msg $color $format "$message"
