@objc private func panGestureRecognizer1Occur(_ sender: UIPanGestureRecognizer) {
    guard let cardContainerView = sender.view, cardContainerView == cardView1 else { return }
    let translation = sender.translation(in: view)
    let newOrigin = CGPoint(x: cardView1.frame.origin.x + translation.x, y: cardView1.frame.origin.y + translation.y)
    cardView1.frame = CGRect(origin: newOrigin, size: cardView1.frame.size)
    sender.setTranslation(.zero, in: view) // Reset the translation to avoid cumulative values

    cardDraggingOccured(cardView1Frame: cardView1.frame, cardView2Frame: cardView2.frame)
}

@objc private func panGestureRecognizer2Occur(_ sender: UIPanGestureRecognizer) {
    guard let cardContainerView = sender.view, cardContainerView == cardView2 else { return }
    let translation = sender.translation(in: view)
    let newOrigin = CGPoint(x: cardView2.frame.origin.x + translation.x, y: cardView2.frame.origin.y + translation.y)
    cardView2.frame = CGRect(origin: newOrigin, size: cardView2.frame.size)
    sender.setTranslation(.zero, in: view) // Reset the translation to avoid cumulative values

    cardDraggingOccured(cardView1Frame: cardView1.frame, cardView2Frame: cardView2.frame)
}
