function convertFontFamilyToUppercase(cssDeclaration) {
  // Extract the font family name from the CSS declaration
  const fontFamilyRegex = /'([^']+)'/;
  const fontFamilyMatch = cssDeclaration.match(fontFamilyRegex);

  if (fontFamilyMatch) {
    const fontFamily = fontFamilyMatch[1];
    const uppercaseFontFamily = fontFamily.toUpperCase();

    // Replace the font family in the CSS declaration with the uppercase version
    const updatedDeclaration = cssDeclaration.replace(fontFamily, uppercaseFontFamily);

    return updatedDeclaration;
