class UserRepository {
  private createdUser: User[] = [];

  async create(register: RegisterDomain): Promise<void> {
    const existingUser = this.getUserByUsername(register.user);
    if (existingUser.length > 0) {
      throw new ConflictException();
    }
    this.createdUser.push(new User(register.user, register.pwd, register.registrationDate));
  }

  async login(credentials: Credentials): Promise<User> {
    const users = this.getUserByUsername(credentials.user);

    if (users.length === 0) {
      throw new NotFoundException();
    }
    if (users.length > 1) {
      throw new ConflictException('Multiple users found with the same username');
    }

    const user = users[0];

    if (user.user === credentials.user && user.pwd === credentials.pwd) {
      return user;
    } else {
      throw new UnauthorizedException();
    }
  }

  private getUserByUsername(username: string): User[] {
    return this.createdUser.filter(user => user.user === username);
  }
}
```

