def makeFrame(s):
    if not s:
        return ""

    words = s.split()
    max_length = max(len(word) for word in words)
    frame_width = max_length + 4  # 2 characters padding on each side

    frame = ["*" * frame_width]
    for word in words:
        frame.append("* " + word.ljust(max_length) + " *")
    frame.append("*" * frame_width)

    return "\n".join(frame)
```

