class Employee {
  constructor(name, age, department, salary) {
    this.name = name;
    this.age = age;
    this.department = department;
    this.salary = salary;
  }

  getDetails() {
    return `Name: ${this.name}, Age: ${this.age}, Department: ${this.department}, Salary: ${this.salary}`;
  }

  changeDepartment(newDepartment) {
    if (typeof newDepartment !== "string" || newDepartment.length < 3) {
      throw new Error("Invalid department name");
    }
    this.department = newDepartment;
  }

  incrementSalary(incrementAmount) {
    if (typeof incrementAmount !== "number" || incrementAmount <= 0 || incrementAmount > (this.salary * 0.1)) {
      throw new Error("Invalid increment amount");
    }
    this.salary += incrementAmount;
  }

  getSalary() {
    return this.salary;
  }

  static getAverageSalary(employees) {
    if (!Array.isArray(employees) || employees.length < 10) {
      throw new Error("Invalid employees array");
    }
    let totalSalary = 0;
    employees.forEach((employee) => {
      if (!employee.hasOwnProperty("salary") || typeof employee.salary !== "number") {
        throw new Error("Invalid salary property");
      }
      totalSalary += employee.salary;
    });
    return totalSalary / employees.length;
  }

  static createEmployee(name, age, department, salary) {
    if (!name || !age || !department || !salary) {
      throw new Error("Missing parameters");
    }
    return new Employee(name, age, department, salary);
  }

  static sortEmployeesBySalary(employees) {
    if (!Array.isArray(employees)) {
      throw new Error("Invalid employees array");
    }
    return employees.sort((a, b) => b.salary - a.salary);
  }
}

