Here's the implementation of the bubble sort algorithm in JavaScript to sort the given array based on the "age" attribute, while ignoring objects with a negative age value:

```javascript
const array = [
  {name: "John", age: 25},
  {name: "Jane", age: -5},
  {name: "Adam", age: 30},
  {name: "Emily", age: 22},
];

function bubbleSort(arr) {
  const n = arr.length;

  for (let i = 0; i < n - 1; i++) {
    let swapped = false;

    for (let j = 0; j < n - i - 1; j++) {
      if (arr[j].age < 0 || arr[j + 1].age < 0) {
        continue; // Ignore objects with negative age values
      }

      if (arr[j].age > arr[j + 1].age) {
        // Swap the objects
        [arr[j], arr[j + 1]] = [arr[j + 1], arr[j]];
        swapped = true;
      }
    }

    if (!swapped) {
      break; // Array is already sorted
    }
  }

  return arr;
}

const sortedArray = bubbleSort(array);
console.log(sortedArray);
```

